mapper.select:
SELECT A.CTKEY, A.POHDKEY, A.PODTKEY , A.OWKEY, A.ICKEY, A.SBKEY, A.SBKEY, A.ICUTKEY , A.EXQTY, A.CFQTY, A.UOM, A.COSTPRICE, A.WKSTATUS , A.UDF1, A.UDF2, A.UDF3 , B.POHDTYPE FROM TWORK_INFO_PO_DT A ,TWORK_INFO_PO_HD B WHERE A.CTKEY = B.CTKEY AND A.POHDKEY = B.POHDKEY AND A.CTKEY = #{ctkey} AND A.POHDKEY = #{pohdkey}
AND A.WKSTATUS IN
#{listWkstatus}


SELECT A.CTKEY, A.POHDKEY, A.PODTKEY
    , A.OWKEY, A.ICKEY, A.SBKEY, A.SBKEY, A.ICUTKEY
    , A.EXQTY, A.CFQTY, A.UOM, A.COSTPRICE, A.WKSTATUS
    , A.UDF1, A.UDF2, A.UDF3
    , B.POHDTYPE
 FROM TWORK_INFO_PO_DT A
    ,TWORK_INFO_PO_HD B
WHERE A.CTKEY = B.CTKEY
    AND A.CTKEY = #{ctkey}
    AND A.POHDKEY = #{pohdkey}	
    AND A.OWKEY = #{owkey}
    AND A.ICKEY = #{ickey}


	AND A.UOM = #{uom}

ORDER BY A.PODTKEY ASC

mapper.update:

UPDATE TWORK_INFO_PO_DT SET
	CFQTY = CFQTY + #{ibqty}
	,NET_WGT = NET_WGT + #{net_wgt_in}
	,UPDATEDATE = #{sysdate}
	,UPDATEURKEY = #{updateurkey}
WHERE CTKEY = #{ctkey}
    AND POHDKEY = #{pohdkey}
	AND PODTKEY = #{podtkey}


UPDATE TWORK_INFO_PO_DT SET
	WKSTATUS = #{wkstatus}
	,UPDATEDATE = #{sysdate}
	,UPDATEURKEY = #{updateurkey}
WHERE CTKEY = #{ctkey}
    AND POHDKEY = #{pohdkey}
	AND PODTKEY = #{podtkey}


UPDATE TWORK_INFO_PO_HD SET
	WKSTATUS = #{wkstatus}
	,UPDATEDATE = #{sysdate}
	,UPDATEURKEY = #{updateurkey}
WHERE CTKEY = #{ctkey}
    AND POHDKEY = #{pohdkey}
